# #通过sku获取链接
# proxy.proxy_pool()
#获取stock数据
for i in list1:
    max_retries = 50  # 设置最大重试次数
    retries = 0
    a = 1

    while retries < max_retries:
        try:
            # 尝试访问StockX网站
            proxy.browser.get(i)
            # proxy.browser.wait(1)
            proxy.browser.ele('@class:chakra-text css-pxl067').scroll.to_see()
            sku = proxy.browser.ele('@class:chakra-text css-pxl067').text
            break  # 如果没有异常发生，退出循环
        except Exception as e:
            retries += 1  # 增加重试计数
            print(f"An error occurred with SKU {sku} on : {e}")
            if retries == max_retries:
                print("stock反爬太牛x，我们败下阵来")
                proxy.browser.close()
                break  # 达到最大重试次数，退出循环
            else:
                # 等待一段时间后重试
                proxy.browser.close()
                time.sleep(1)
                if a == 1:
                    proxy.browser = proxy.shuju(a=a)  # 重新初始化浏览器
                    print('edge')
                    a = 2
                else:
                    proxy.browser = proxy.shuju(a=a)
                    print('Chrom')
                    a = 1
                proxy.proxy_pool()  # 重新设置代理
    print(sku)
    proxy.browser.ele('css:.chakra-button.css-1hd42sk').click(by_js=type)
    value = proxy.browser.ele('@class:chakra-table css-5605sr').html
    datas = re.findall(r'class="css-1eem9s7">(.*?)</td>', value, re.DOTALL)
    print(datas)
    sizes = re.findall(r'class="css-13p53ku">US (.*?)</td>', value, re.DOTALL)
    print(sizes)
    prices = re.findall('<p class="chakra-text css-6tf6w0">US\\$(.*?)</p>', value, re.DOTALL)
    print(prices)


    # 保存到Excel文件
    # df.to_excel("shuju.xlsx", index=False)
    df = pd.read_excel('查价格.xlsx', sheet_name='Sheet1')

    prices = [int(price) for price in prices]  # 将prices列表中的字符串转换为整数
    lists = []
    if '货号' in df.columns and '码数' in df.columns and '价格' in df.columns:
        for size in sizes:  # 使用sizes变量代替value2
            try:
                matching_rows = df[(df['货号'] == sku) & (df['码数'].str.contains(size, regex=True, na=False))]
            except:
                matching_rows = df[(df['货号'].str.contains(r'.*' + sku.split('/')[0] + r'.*', regex=True)) &
                                   (df['码数'].str.contains(size.strip(), regex=True))]

            if not matching_rows.empty:
                # 清除价格中的货币符号，并转换为数值类型
                matching_rows['价格'] = matching_rows['价格'].str.replace(r'[^\d.]', '', regex=True)
                matching_rows['价格'] = pd.to_numeric(matching_rows['价格'], errors='coerce')

                # 确保prices列表中的值是整数类型
                for price in prices:
                    if matching_rows['价格'].values[0] > price:
                        lists.append('无利润')

                    else:
                        lists.append('有利润')

            else:
                print(f"未找到货号 '{sku}' 与码数 '{size}' 同时满足条件的行。")
    else:
        print("所需的列名不存在。")
    # 定义时间字符串的格式
    time_format = "%y/%m/%d %p%H:%M"
    # 获取当前时间
    now = datetime.now()
    # 创建一个timedelta对象，表示7天
    seven_days = timedelta(days=7)
    # 计算7天前的时间
    one_week_ago = now - seven_days
    # 初始化结果列表
    results = []
    # 遍历时间字符串列表
    for time_str in datas:
        # 使用正则表达式替换中文的上午和下午为AM和PM
        time_str = re.sub(r'上午', 'AM', time_str)
        time_str = re.sub(r'下午', 'PM', time_str)
        # 将时间字符串转换为datetime对象
        given_time = datetime.strptime(time_str, time_format)
        # 比较时间
        if given_time < one_week_ago:
            results.append(0)
        else:
            results.append(1)

    df_shuju = pd.DataFrame(columns=["sku", "size", "price", "利润", "近7天销量"])

    # 将数据添加到DataFrame中
    df_shuju = pd.DataFrame()  # 初始化一个空的DataFrame
    for i in range(len(datas)):
        row = {"sku": sku, "size": sizes[i], "price": prices[i], "利润": lists[i], "近7天销量": results[i]}
        df_shuju = pd.concat([df_shuju, pd.DataFrame([row])], ignore_index=True)

    # 使用ExcelWriter以追加模式写入Excel文件
    with pd.ExcelWriter("shuju.xlsx", mode='a', engine='openpyxl', if_sheet_exists='overlay') as writer:
        # 如果Excel文件中已经存在DataFrame的sheet，则overlay选项会将新数据追加到现有sheet的下一行
        df_shuju.to_excel(writer, index=False, sheet_name='Sheet1', startrow=writer.sheets['Sheet1'].max_row)